import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TeamMember {
  id: number;
  name: string;
  role: string;
  description: string;
  avatarUrl: string;
}

export interface HiveData {
  id: number;
  name: string;
  temperature: number;
  humidity: number;
  weight: number;
  status: 'optimal' | 'warning' | 'critical';
  lastUpdated: Date;
}

export interface Bee {
  id: number;
  x: number;
  y: number;
  vx: number;
  vy: number;
  scale: number;
}

import { HiveData } from '../types';

// The actual URL from the prompt. 
// Note: In a browser environment, fetching directly from a remote HTTP server that doesn't enable CORS 
// will fail. This service includes a robust fallback to ensure the UI works for demonstration.
const DATA_URL = 'https://lycabbio.fr/donnees.json'; // Assumed filename based on standard projects

/**
 * Simulates fetching data if the real endpoint is unavailable or CORS blocks it.
 * This ensures the layout requested is visible immediately.
 */
const generateMockData = (): HiveData[] => {
  return Array.from({ length: 9 }, (_, i) => {
    const temp = 33 + Math.random() * 4; // 33-37°C is normal
    const humidity = 50 + Math.random() * 20;
    const weight = 15 + Math.random() * 30; // 15-45kg

    let status: HiveData['status'] = 'optimal';
    if (temp < 32 || temp > 38) status = 'warning';

    return {
      id: i + 1,
      name: `Ruche ${i + 1}`,
      temperature: parseFloat(temp.toFixed(1)),
      humidity: Math.round(humidity),
      weight: parseFloat(weight.toFixed(2)),
      status: status,
      lastUpdated: new Date()
    };
  });
};

export const fetchHiveData = async (): Promise<HiveData[]> => {
  try {
    // Attempt to fetch real data
    // We use a short timeout so we fallback quickly if it hangs
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 2000);

    const response = await fetch(DATA_URL, { signal: controller.signal });
    clearTimeout(timeoutId);

    if (!response.ok) {
      throw new Error('Network response was not ok');
    }

    const rawData = await response.json();

    // Assuming the API returns an array or object we map to our format
    // This part depends heavily on the specific JSON structure of lycabbio.fr
    // For safety, we map whatever comes back to our HiveData structure if possible
    // If not, the catch block triggers the mock data.

    // Placeholder mapping logic (generic)
    return Array.isArray(rawData) ? rawData.map((item: any, index: number) => ({
      id: index + 1,
      name: item.name || `Ruche ${index + 1}`,
      temperature: Number(item.temperature || item.temp || 0),
      humidity: Number(item.humidity || item.hum || 0),
      weight: Number(item.mass || item.poids || item.weight || 0),
      status: 'optimal',
      lastUpdated: new Date()
    })) : generateMockData();

  } catch (error) {
    console.warn("Could not fetch live data from Lycabbio (likely CORS or wrong file path). Using simulation data.", error);
    return generateMockData();
  }
};

import React, { useEffect, useState, useRef } from 'react';
import { Bee } from '../types';

const BEE_COUNT = 15;

const BeeAnimation: React.FC = () => {
  const [bees, setBees] = useState<Bee[]>([]);
  const requestRef = useRef<number>();

  useEffect(() => {
    // Initialize bees with random positions
    const initialBees: Bee[] = Array.from({ length: BEE_COUNT }, (_, i) => ({
      id: i,
      x: Math.random() * window.innerWidth,
      y: Math.random() * window.innerHeight,
      vx: (Math.random() - 0.5) * 2, // Velocity X
      vy: (Math.random() - 0.5) * 2, // Velocity Y
      scale: 0.5 + Math.random() * 0.5
    }));
    setBees(initialBees);

    const animate = () => {
      setBees(prevBees => prevBees.map(bee => {
        let { x, y, vx, vy } = bee;

        // Random jitter to movement
        vx += (Math.random() - 0.5) * 0.2;
        vy += (Math.random() - 0.5) * 0.2;

        // Limit speed
        const maxSpeed = 3;
        const speed = Math.sqrt(vx * vx + vy * vy);
        if (speed > maxSpeed) {
          vx = (vx / speed) * maxSpeed;
          vy = (vy / speed) * maxSpeed;
        }

        x += vx;
        y += vy;

        // Bounce off edges
        if (x < -50) x = window.innerWidth + 50;
        if (x > window.innerWidth + 50) x = -50;
        if (y < -50) y = window.innerHeight + 50;
        if (y > window.innerHeight + 50) y = -50;

        return { ...bee, x, y, vx, vy };
      }));
      requestRef.current = requestAnimationFrame(animate);
    };

    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  return (
    <div className="fixed inset-0 pointer-events-none z-50 overflow-hidden">
      {bees.map((bee) => (
        <div
          key={bee.id}
          className="absolute will-change-transform"
          style={{
            transform: `translate(${bee.x}px, ${bee.y}px) scale(${bee.scale}) rotate(${Math.atan2(bee.vy, bee.vx) * (180 / Math.PI) + 90}deg)`,
            transition: 'transform 0.1s linear'
          }}
        >
           {/* SVG Bee Icon */}
           <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            <path d="M8 8C8 8 3 10 3 14C3 18 7 19 8 16" stroke="#000" strokeWidth="1.5" strokeLinecap="round"/>
            <path d="M16 8C16 8 21 10 21 14C21 18 17 19 16 16" stroke="#000" strokeWidth="1.5" strokeLinecap="round"/>
            <ellipse cx="12" cy="14" rx="4" ry="7" fill="#FBBF24" stroke="#000" strokeWidth="1.5"/>
            <path d="M9 12H15" stroke="#000" strokeWidth="1.5"/>
            <path d="M9 15H15" stroke="#000" strokeWidth="1.5"/>
            <path d="M9 18H15" stroke="#000" strokeWidth="1.5"/>
          </svg>
        </div>
      ))}
    </div>
  );
};

export default BeeAnimation;

