  const requestRef = useRef<number>();

  useEffect(() => {
    // We want bees to hover around the bottom section of the screen where hives likely are
    // Assuming standard 1080p screen, hives are usually in the bottom 40%
    const hiveZoneY = window.innerHeight * 0.7; 

    const initialBees: Bee[] = Array.from({ length: BEE_COUNT }, (_, i) => ({
      id: i,
      x: window.innerWidth / 2 + (Math.random() - 0.5) * 200, // Start roughly center width
      y: hiveZoneY + (Math.random() - 0.5) * 100, // Start around hive height
      vx: (Math.random() - 0.5) * 4,
      vy: (Math.random() - 0.5) * 2, 
      scale: 0.6 + Math.random() * 0.4,
      angle: 0
    }));
    setBees(initialBees);

    const animate = () => {
      setBees(prevBees => prevBees.map(bee => {
        let { x, y, vx, vy, angle } = bee;

        // More functional movement: "Patrol" behavior
        // Add a slight attraction to the center Y (hive line)
        const hiveZoneY = window.innerHeight * 0.75;
        const targetY = hiveZoneY;

        // Attraction force to vertical center of hive zone
        vy += (targetY - y) * 0.001;

        // Random wandering noise
        vx += (Math.random() - 0.5) * 0.3;
        vy += (Math.random() - 0.5) * 0.3;

        // Dampening to prevent infinite acceleration
        vx *= 0.99;
        vy *= 0.99;

        // Max speed limit
        const speed = Math.sqrt(vx * vx + vy * vy);
        if (speed > 4) {
          vx = (vx / speed) * 4;
          vy = (vy / speed) * 4;
        }

        x += vx;
        y += vy;

        // Soft boundaries - instead of wrapping, turn them around gently
        // Left/Right boundaries
        if (x < -50) x = window.innerWidth + 50; 
        if (x > window.innerWidth + 50) x = -50;

        // Top/Bottom boundaries (Keep them in the bottom half mostly)
        if (y < window.innerHeight * 0.4) vy += 0.2; // Push down if too high
        if (y > window.innerHeight - 50) vy -= 0.2; // Push up if too low

        // Calculate rotation angle based on velocity
        angle = Math.atan2(vy, vx) * (180 / Math.PI) + 90;

        return { ...bee, x, y, vx, vy, angle };
      }));
      requestRef.current = requestAnimationFrame(animate);
    };

    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, []);

  return (
    <div className="fixed inset-0 pointer-events-none z-50 overflow-hidden">
      {bees.map((bee) => (
        <div
          key={bee.id}
          className="absolute will-change-transform drop-shadow-lg"
          style={{
            transform: `translate(${bee.x}px, ${bee.y}px) scale(${bee.scale}) rotate(${bee.angle}deg)`,
            transition: 'transform 0.05s linear' // Faster update for smoother motion
          }}
        >
           {/* Detailed SVG Bee */}
           <svg width="32" height="32" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg">
            {/* Wings with transparency for motion blur effect */}
            <path d="M8 8C8 8 2 6 2 12C2 16 7 16 8 16" fill="white" fillOpacity="0.7" stroke="#000" strokeWidth="0.5"/>
            <path d="M16 8C16 8 22 6 22 12C22 16 17 16 16 16" fill="white" fillOpacity="0.7" stroke="#000" strokeWidth="0.5"/>

            {/* Body */}
            <ellipse cx="12" cy="14" rx="5" ry="8" fill="#F59E0B" stroke="#451a03" strokeWidth="1.5"/>

            {/* Stripes */}
            <path d="M8 12H16" stroke="#451a03" strokeWidth="2" strokeLinecap="round"/>
            <path d="M8 15H16" stroke="#451a03" strokeWidth="2" strokeLinecap="round"/>
            <path d="M9 18H15" stroke="#451a03" strokeWidth="2" strokeLinecap="round"/>

            {/* Eyes */}
            <circle cx="10" cy="9" r="1" fill="#000"/>
            <circle cx="14" cy="9" r="1" fill="#000"/>
          </svg>
        </div>
      ))}
    </div>
  );
};

