const DATA_URL = 'https://lycabbio.fr/PHP/currentData.php';

/**
 * Simulates fetching data if the real endpoint is unavailable or CORS blocks it.
 */
const generateMockData = (): HiveData[] => {
  return Array.from({ length: 9 }, (_, i) => {
    const temp = 33 + Math.random() * 4; // 33-37°C is normal
    const humidity = 50 + Math.random() * 20;
    const weight = 15 + Math.random() * 30; // 15-45kg

    let status: HiveData['status'] = 'optimal';
    if (temp < 32 || temp > 38) status = 'warning';

    return {
      id: i + 1,
      name: `Ruche ${i + 1}`,
      temperature: parseFloat(temp.toFixed(1)),
      humidity: Math.round(humidity),
      weight: parseFloat(weight.toFixed(2)),
      status: status,
      lastUpdated: new Date()
    };
  });
};

export const fetchHiveData = async (): Promise<HiveData[]> => {
  try {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 3000); // 3 second timeout

    const response = await fetch(DATA_URL, { signal: controller.signal });
    clearTimeout(timeoutId);

    if (!response.ok) {
      throw new Error('Network response was not ok');
    }

    const rawData = await response.json();

    // Mapping logic to handle potential variations in JSON keys from the PHP script
    // We expect an array of objects.
    if (Array.isArray(rawData)) {
      return rawData.map((item: any, index: number) => {
        // Safe number parsing
        const temp = parseFloat(item.temperature || item.Temperature || item.temp || 0);
        const hum = parseFloat(item.humidity || item.Humidity || item.hum || 0);
        const mass = parseFloat(item.weight || item.Weight || item.masse || item.Masse || item.poids || 0);

        // Simple status logic
        let status: 'optimal' | 'warning' | 'critical' = 'optimal';
        if (temp > 40 || temp < 10) status = 'warning';

        // Use ID from DB if available, otherwise index
        const id = item.id ? parseInt(item.id) : index + 1;

        return {
          id: id,
          name: item.nom || item.name || `Ruche ${id}`,
          temperature: parseFloat(temp.toFixed(1)),
          humidity: Math.round(hum),
          weight: parseFloat(mass.toFixed(2)),
          status: status,
          lastUpdated: new Date() // PHP might usually return current state, so 'now' is acceptable
        };
      });
    }

    return generateMockData();

  } catch (error) {
    console.warn("Could not fetch live data from Lycabbio. Using simulation data.", error);
    return generateMockData();
  }
};

