const App: React.FC = () => {
  const [hives, setHives] = useState<HiveData[]>([]);
  const [filteredHives, setFilteredHives] = useState<HiveData[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [isDarkMode, setIsDarkMode] = useState<boolean>(false);
  const [selectedHive, setSelectedHive] = useState<HiveData | null>(null);
  const [filterType, setFilterType] = useState<'all' | 'warning' | 'heavy'>('all');

  // Load data function
  const loadData = async () => {
    // Only show full loader on initial load
    if (hives.length === 0) setLoading(true);

    const data = await fetchHiveData();
    setHives(data);

    // Simulate a minimum loading time for the animation (only first time)
    if (hives.length === 0) {
        setTimeout(() => setLoading(false), 2000);
    }
  };

  // Filter Logic
  useEffect(() => {
    let result = [...hives];
    if (filterType === 'warning') {
        result = result.filter(h => h.status === 'warning' || h.status === 'critical');
    } else if (filterType === 'heavy') {
        result = result.sort((a, b) => b.weight - a.weight);
    } else {
        // Default sort by ID
        result = result.sort((a, b) => a.id - b.id);
    }
    setFilteredHives(result);
  }, [hives, filterType]);

  // Initial load and interval
